// AuthenticateUser checks the provided username and password against the MySQL database.
// Returns true if the credentials match, false otherwise.
func AuthenticateUser(db *sql.DB, username, password string) (bool, error) {
	var hashedPassword string

	// Use parameterized query to prevent SQL injection
	query := "SELECT password FROM users WHERE username = ?"
	err := db.QueryRow(query, username).Scan(&hashedPassword)
	if err != nil {
		if err == sql.ErrNoRows {
			// User not found
			return false, nil
		}
		return false, fmt.Errorf("error querying database: %w", err)
	}

	// Compare the stored hashed password with the provided password
	err = bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(password))
	if err != nil {
		if err == bcrypt.ErrMismatchedHashAndPassword {
			return false, nil
		}
		return false, fmt.Errorf("error comparing passwords: %w", err)
	}

	return true, nil
}

// HashPassword generates a bcrypt hash of the given password.
// Useful for storing passwords when creating or updating users.
func HashPassword(password string) (string, error) {
	hashedBytes, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return "", fmt.Errorf("error hashing password: %w", err)
	}
	return string(hashedBytes), nil
}

// ConnectDB establishes a connection to the MySQL database.
func ConnectDB(dsn string) (*sql.DB, error) {
	db, err := sql.Open("mysql", dsn)
	if err != nil {
		return nil, fmt.Errorf("error opening database: %w", err)
	}

	err = db.Ping()
	if err != nil {
		db.Close()
		return nil, fmt.Errorf("error connecting to database: %w", err)
	}

	return db, nil
}

